CREATE TABLE cuentas (id SERIAL PRIMARY KEY, nombre VARCHAR(120), email VARCHAR(255) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, rol VARCHAR(20) NOT NULL DEFAULT 'familiar' CHECK (rol IN ('familiar','mayor','admin','soporte')), verificado BOOLEAN NOT NULL DEFAULT FALSE, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE personas (id SERIAL PRIMARY KEY, nombre VARCHAR(120) NOT NULL, edad SMALLINT, telefono VARCHAR(20), email VARCHAR(255), preferencias JSONB NOT NULL DEFAULT '{}'::jsonb, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE accesos (id SERIAL PRIMARY KEY, cuenta_id INTEGER NOT NULL REFERENCES cuentas(id) ON DELETE CASCADE, persona_id INTEGER NOT NULL REFERENCES personas(id) ON DELETE CASCADE, parentesco VARCHAR(40), es_principal BOOLEAN NOT NULL DEFAULT FALSE, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), UNIQUE (cuenta_id, persona_id));
CREATE TABLE pulseras (id SERIAL PRIMARY KEY, persona_id INTEGER UNIQUE REFERENCES personas(id) ON DELETE SET NULL, codigo_activacion VARCHAR(20) NOT NULL UNIQUE, id_publico VARCHAR(20) UNIQUE, estado VARCHAR(20) NOT NULL DEFAULT 'sin_activar' CHECK (estado IN ('sin_activar','activada','desconectada','baja')), bateria SMALLINT, firmware VARCHAR(20), ultima_conexion TIMESTAMPTZ, activada_en TIMESTAMPTZ, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE contactos_emergencia (id SERIAL PRIMARY KEY, persona_id INTEGER NOT NULL REFERENCES personas(id) ON DELETE CASCADE, nombre VARCHAR(120) NOT NULL, telefono VARCHAR(20) NOT NULL, parentesco VARCHAR(40), prioridad SMALLINT NOT NULL DEFAULT 1, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE recordatorios (id SERIAL PRIMARY KEY, persona_id INTEGER NOT NULL REFERENCES personas(id) ON DELETE CASCADE, tipo VARCHAR(30) NOT NULL CHECK (tipo IN ('paseo','llamada_familiar','medicacion','otro')), titulo VARCHAR(120), hora TIME NOT NULL, dias_semana SMALLINT[] NOT NULL DEFAULT '{0,1,2,3,4,5,6}', activo BOOLEAN NOT NULL DEFAULT TRUE, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE interacciones (id SERIAL PRIMARY KEY, pulsera_id INTEGER NOT NULL REFERENCES pulseras(id) ON DELETE CASCADE, recordatorio_id INTEGER REFERENCES recordatorios(id) ON DELETE SET NULL, tipo VARCHAR(30) NOT NULL, respuesta VARCHAR(10), detalle TEXT, ocurrido_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE ubicaciones (id SERIAL PRIMARY KEY, pulsera_id INTEGER NOT NULL REFERENCES pulseras(id) ON DELETE CASCADE, lat NUMERIC(9,6) NOT NULL, lng NUMERIC(9,6) NOT NULL, precision_m SMALLINT, bateria SMALLINT, registrado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE alertas_panico (id SERIAL PRIMARY KEY, pulsera_id INTEGER NOT NULL REFERENCES pulseras(id) ON DELETE CASCADE, lat NUMERIC(9,6), lng NUMERIC(9,6), estado VARCHAR(20) NOT NULL DEFAULT 'enviada' CHECK (estado IN ('enviada','atendida','falsa_alarma')), contactos_avisados INTEGER, atendida_por INTEGER REFERENCES cuentas(id) ON DELETE SET NULL, atendida_en TIMESTAMPTZ, disparada_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE suscripciones (id SERIAL PRIMARY KEY, cuenta_id INTEGER NOT NULL REFERENCES cuentas(id) ON DELETE CASCADE, persona_id INTEGER REFERENCES personas(id) ON DELETE SET NULL, plan VARCHAR(30) NOT NULL DEFAULT 'mensual', precio NUMERIC(6,2) NOT NULL DEFAULT 14.90, estado VARCHAR(20) NOT NULL DEFAULT 'activa' CHECK (estado IN ('activa','pausada','cancelada','impagada')), stripe_subscription_id VARCHAR(120), fecha_inicio DATE NOT NULL DEFAULT CURRENT_DATE, proxima_renovacion DATE, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE pagos (id SERIAL PRIMARY KEY, suscripcion_id INTEGER NOT NULL REFERENCES suscripciones(id) ON DELETE CASCADE, importe NUMERIC(6,2) NOT NULL, estado VARCHAR(20) NOT NULL DEFAULT 'pendiente' CHECK (estado IN ('pendiente','completado','fallido','reembolsado')), stripe_payment_id VARCHAR(120), pagado_en TIMESTAMPTZ, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX idx_accesos_cuenta ON accesos(cuenta_id);
CREATE INDEX idx_accesos_persona ON accesos(persona_id);
CREATE INDEX idx_interacciones_pulserafecha ON interacciones(pulsera_id, ocurrido_en DESC);
CREATE INDEX idx_ubicaciones_pulserafecha ON ubicaciones(pulsera_id, registrado_en DESC);
CREATE INDEX idx_alertas_pulserafecha ON alertas_panico(pulsera_id, disparada_en DESC);
